// Acting Component
instance PMSMActuator : DTDFVocab:ActingComponent [
    base:desc "Permanent magnet synchronous motor (PMSM) driven by a gearhead and a cycloidal gear set. Controlled via a Siemens SINUMERIK 840D servo processor that translates current setpoints into torque outputs."
]

// Sensing Components
instance MotorShaftEncoder : DTDFVocab:SensingComponent [
    base:desc "Absolute position encoder mounted directly on the motor shaft, providing rotational angle measurement."
    DTDFVocab:producedData MotorTelemetryPayload
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Absolute position encoder behind the gearbox, providing redundant angle measurement."
    DTDFVocab:producedData MotorTelemetryPayload
]

// Data Transmitted
instance MotorTelemetryPayload : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorShaftEncoder, GearboxEncoder
]

// Data
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time-series data of motor current, validated for range and timestamp consistency."
    DTDFVocab:fromData MotorTelemetryPayload
    DTDFVocab:inputTo MQTTClientEnabler
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Time-series data of actuator angle, mapped to standardized units."
    DTDFVocab:fromData MotorTelemetryPayload
    DTDFVocab:inputTo MQTTClientEnabler
]

// Enablers
instance MQTTClientEnabler : DTDFVocab:Enabler [
    base:desc "MQTT client facilitating real‑time publish/subscribe to stream telemetry at 500 ms intervals."
    DTDFVocab:enables TelemetryIngestionService
]

instance LowPassFilterEnabler : DTDFVocab:Enabler [
    base:desc "Fourth-order low-pass filter removing high-frequency noise before data is stored."
]

instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML modeling tool used for requirements, functional, logical, and product architecture."
    DTDFVocab:enables SimulationService
]

instance ACMEEnabler : DTDFVocab:Enabler [
    base:desc "ACME Architecture Description Language used to capture component‑and‑connector detail."
    DTDFVocab:enables SimulationService
]

instance AADLEnabler : DTDFVocab:Enabler [
    base:desc "AADL used to capture component‑and‑connector detail and low‑level behavior."
    DTDFVocab:enables SimulationService
]

instance MontiArcEnabler : DTDFVocab:Enabler [
    base:desc "MontiArc ADL used for component models and automaton behavior."
    DTDFVocab:enables SimulationService
]

instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MathWorks Simulink tool used for dynamic simulation of the drive."
    DTDFVocab:enables SimulationService
]

instance CPPJavaEnabler : DTDFVocab:Enabler [
    base:desc "C++/Java compiler and runtime environment for code generation and execution."
    DTDFVocab:enables SimulationService
]

// Services
instance TelemetryIngestionService : DTDFVocab:Service [
    base:desc "Ingests telemetry data via MQTT, performs quality checks (range validation, timestamp consistency), applies preprocessing, and stores decimated data in a time‑series database."
    DTDFVocab:provides ProcessTelemetryEventAction
]

instance ActuationService : DTDFVocab:Service [
    base:desc "Controls actuator torque and speed through the Siemens SINUMERIK processor, exposing functional groups CONTROL.TORQUE, CONTROL.SPEED, and SAFETY.FLAG."
    DTDFVocab:provides ApplyTorqueSetpointAction
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Simulates drive dynamics and validates models against sensor data using Simulink and MontiArc."
    DTDFVocab:provides RunSimulinkModelAction
]

// Actions
instance ProcessTelemetryEventAction : DTDFVocab:Action [
    base:desc "Processes quality‑checked telemetry data and updates the digital twin state machine."
    DTDFVocab:IsAutomatic true
]

instance ApplyTorqueSetpointAction : DTDFVocab:Action [
    base:desc "Applies a new torque setpoint to the actuator via the SINUMERIK controller."
    DTDFVocab:IsAutomatic true
]

instance RunSimulinkModelAction : DTDFVocab:Action [
    base:desc "Executes Simulink simulation of drive dynamics and logs results."
    DTDFVocab:IsAutomatic true
]

// Models
instance SimulinkDriveModel : DTDFVocab:Model [
    base:desc "Simulink model representing the drive dynamics, including motor, gearbox, and control loop."
    DTDFVocab:inputTo SimulinkEnabler
]

instance MontiArcAutomatonModel : DTDFVocab:Model [
    base:desc "MontiArc automaton modeling the drive system behavior."
    DTDFVocab:inputTo MontiArcEnabler
]

instance SysMLFunctionalModel : DTDFVocab:Model [
    base:desc "SysML functional architecture model including functional blocks and interfaces."
    DTDFVocab:inputTo SysMLEnabler
]

instance ACMEComponentModel : DTDFVocab:Model [
    base:desc "ACME model capturing component and connector detail at product level."
    DTDFVocab:inputTo ACMEEnabler
]

instance AADLModel : DTDFVocab:Model [
    base:desc "AADL model detailing component interactions and real‑time properties."
    DTDFVocab:inputTo AADLEnabler
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The overall orchestration is grounded in Model-Based Systems Engineering (MBSE) practices, leveraging system modeling languages such as SysML for functional and logical architecture, and architecture description languages (ADLs) like ACME, AADL, MontiArc, or SysML IBDs for component and connector descriptions. These models are often combined with simulation tools such as MathWorks Simulink or general-purpose code (C++/Java) to describe behavior. Coordination at the constellation level hinges on these integrated representations, with resource management and system-wide coordination inferred from the combined usage of methodology frameworks such as RFLP, OOSEM, SPES, or SMArDT, though explicit orchestration patterns are not detailed."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Information from the physical asset is transmitted via MQTT over TCP/IP. Topics are organized per subsystem (e.g., /sensor/current, /actuator/angle). The MQTT broker is positioned on the local edge gateway, providing non‑blocking publish/subscribe semantics. No specific QoS level is mandated in the source; reliability expectations are left implicit."
]
